// Pure classifier for migration SQL: given the raw text of a migration file,
// decide whether it contains a HARD-destructive statement — one that removes or
// renames a schema object the branch's code may still reference, so a worktree
// DB that applied it (but whose branch lacks the file) can crash a read path.
//
// Pure string → object: no DB, no git, no I/O. The migration SQL is machine-
// generated by drizzle (plus hand-written backfills), so reasonable-effort
// tokenization — comment-strip, then per-statement keyword scan — is enough.

// HARD kinds: the old name is gone, so code still using it crashes.
export type DestructiveKind = "drop-table" | "drop-column" | "rename";

export interface DestructiveClassification {
  // true iff any HARD (DestructiveKind) statement is present.
  destructive: boolean;
  statements: Array<{ kind: DestructiveKind; text: string }>;
}

// Deliberately OUT of the blocking set (soft reshapes that rarely crash a read
// path — revisit only if a real case appears): DROP CONSTRAINT,
// ALTER COLUMN ... TYPE, SET NOT NULL. We do NOT classify these as destructive.
const MATCHERS: Array<{ kind: DestructiveKind; re: RegExp }> = [
  { kind: "drop-table", re: /\bDROP\s+TABLE\b/i },
  { kind: "drop-column", re: /\bDROP\s+COLUMN\b/i },
  // ALTER TABLE ... RENAME — covers both `RENAME TO` (table rename) and
  // `RENAME COLUMN` (column rename). Anchored on ALTER TABLE so a stray RENAME
  // keyword elsewhere can't misfire.
  { kind: "rename", re: /\bALTER\s+TABLE\b[\s\S]*?\bRENAME\b/i },
];

// Strip SQL comments so commented-out DDL (and drizzle's own
// `--> statement-breakpoint` markers) never trip the keyword scan.
function stripComments(sql: string): string {
  return sql
    .replace(/\/\*[\s\S]*?\*\//g, " ") // /* block */ comments
    .replace(/--.*$/gm, ""); // -- line comments (through end of line)
}

// Collapse a statement to a short, single-line snippet so the check can name the
// dropped/renamed object in its message.
function snippet(statement: string): string {
  const oneLine = statement.replace(/\s+/g, " ").trim();
  return oneLine.length > 200 ? `${oneLine.slice(0, 197)}...` : oneLine;
}

export function classifyMigrationSql(sqlText: string): DestructiveClassification {
  const statements = stripComments(sqlText)
    .split(";")
    .map((s) => s.trim())
    .filter((s) => s.length > 0);

  const found: Array<{ kind: DestructiveKind; text: string }> = [];
  for (const statement of statements) {
    // At most one HARD kind per statement (drizzle emits one DDL per statement);
    // first match wins, so an additive + destructive file yields exactly the
    // destructive entries.
    const match = MATCHERS.find((m) => m.re.test(statement));
    if (match) found.push({ kind: match.kind, text: snippet(statement) });
  }

  return { destructive: found.length > 0, statements: found };
}
